import { NextRequest, NextResponse } from 'next/server';
import { requireAuth } from '@/app/api/_lib/auth';

export async function POST(
    req: NextRequest,
    { params }: { params: Promise<{ action: string }> }
) {
    const auth = await requireAuth();
    if (!auth.authenticated) return auth.response;

    const { action } = await params;

    try {
        const body = await req.json();
        const { inputs, user } = body;

        // Extract tenant for multi-tenancy
        const cookieStore = req.cookies;
        const tenantApiKey = cookieStore.get('tenant_api_key')?.value;
        const xFrappeSiteName = req.headers.get('x-frappe-site-name');
        
        let tenantIdentifier = 'nexus-system';
        if (tenantApiKey) {
            // we could decode it or just use the existence to know it's a tenant
            tenantIdentifier = 'tenant-api-user'; 
        } 
        if (xFrappeSiteName) {
            tenantIdentifier = xFrappeSiteName;
        }

        // Prefer explicit user > extracted tenant > fallback
        const difyUser = user || tenantIdentifier;

        let apiKey = '';

        // Select the correct API Key based on the action
        switch (action) {
            case 'risk-score':
                apiKey = process.env.DIFY_RISK_API_KEY || '';
                break;
            case 'forecast':
                apiKey = process.env.DIFY_FORECAST_API_KEY || '';
                break;
            case 'fraud-check':
                apiKey = process.env.DIFY_FRAUD_API_KEY || '';
                break;
            case 'crm-insights':
                apiKey = process.env.DIFY_CRM_API_KEY || '';
                break;
            default:
                return NextResponse.json({ error: 'Invalid action' }, { status: 400 });
        }

        if (!apiKey) {
            return NextResponse.json({ error: `API Key not configured for action: ${action}` }, { status: 500 });
        }

        // Call Dify API for Workflow apps
        const response = await fetch(`${process.env.DIFY_API_URL}/workflows/run`, {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${apiKey}`,
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                inputs: inputs || {},
                response_mode: 'blocking', // Wait for full answer
                user: difyUser,
            }),
        });

        if (!response.ok) {
            const errorText = await response.text();
            console.error(`Dify API Error [${action}]:`, errorText);
            
            return NextResponse.json({ error: "AI Service Error" }, { status: response.status });
        }

        const responseData = await response.json();

        // Extract the result from the workflow output
        let resultRaw = responseData?.data?.outputs;
        let resultStr = null;

        if (resultRaw) {
            // Find the property that holds the JSON string. Usually users map it to 'text', 'output', 'result', etc.
            if (typeof resultRaw === 'string') {
                resultStr = resultRaw;
            } else if (resultRaw.result && typeof resultRaw.result === 'string') {
                resultStr = resultRaw.result;
            } else if (resultRaw.text && typeof resultRaw.text === 'string') {
                resultStr = resultRaw.text;
            } else if (resultRaw.output && typeof resultRaw.output === 'string') {
                resultStr = resultRaw.output;
            } else {
                // Just grab the first string property available
                const stringKeys = Object.keys(resultRaw).filter(k => typeof resultRaw[k] === 'string');
                if (stringKeys.length > 0) {
                    resultStr = resultRaw[stringKeys[0]];
                } else if (Object.keys(resultRaw).length > 0) {
                    // It might already be a pure object map!
                    resultStr = resultRaw;
                }
            }
        } else if (responseData?.answer) {
             resultStr = responseData.answer;
        }

        let parsedResult = resultStr;
        
        try {
            if (typeof resultStr === 'string') {
                let cleanStr = resultStr.trim();
                
                // Try to extract JSON from markdown block
                const jsonMatch = cleanStr.match(/```json\s*([\s\S]*?)\s*```/);
                const genericMatch = cleanStr.match(/```\s*(\{[\s\S]*?\})\s*```/);
                
                if (jsonMatch && jsonMatch[1]) {
                    cleanStr = jsonMatch[1].trim();
                } else if (genericMatch && genericMatch[1]) {
                    cleanStr = genericMatch[1].trim();
                } else {
                    // Fallback to extracting the first '{' to the last '}'
                    const firstBrace = cleanStr.indexOf('{');
                    const lastBrace = cleanStr.lastIndexOf('}');
                    if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
                        cleanStr = cleanStr.substring(firstBrace, lastBrace + 1).trim();
                    }
                }
                
                if (cleanStr.startsWith('{') || cleanStr.startsWith('[')) {
                    parsedResult = JSON.parse(cleanStr);
                }
            }
        } catch (e) {
            console.warn("Failed to parse AI output as JSON:", resultStr);
            // Keep as string if parsing fails
        }

        return NextResponse.json({ result: parsedResult });

    } catch (error: any) {
        console.error(`AI Action Error [${action}]:`, error);
        return NextResponse.json({ error: error.message || 'Internal Server Error' }, { status: 500 });
    }
}

"use client"

import { useState } from "react"
import Link from "next/link"
import { useRouter } from "next/navigation"

interface AICrmInsightsProps {
  accessibleModules: string[];
  atRiskDeals: any[];
  highProbOpportunities: any[];
}

interface CrmInsightResult {
  executive_summary: string;
  at_risk_analysis?: {
    identified_risk_deals: string[];
    risk_factors: string[];
    recommended_mitigation: string;
  };
  opportunity_analysis?: {
    top_prospects: string[];
    key_drivers: string[];
    recommended_closing_actions: string[];
  };
}

export function AICrmInsights({
  accessibleModules,
  atRiskDeals = [],
  highProbOpportunities = []
}: AICrmInsightsProps) {
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const [insights, setInsights] = useState<CrmInsightResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleGenerateInsights = async () => {
    try {
      setLoading(true);
      setError(null);

      // Prepare payload for the AI
      const payload = {
        at_risk_pipeline: atRiskDeals.map(deal => ({
          customer: deal.customer_name,
          days_inactive: deal.days_since_activity,
          reason: deal.reason
        })),
        high_probability_pipeline: highProbOpportunities.map(opp => ({
          customer: opp.customer_name || opp.party_name,
          stage: opp.sales_stage,
          amount: opp.opportunity_amount,
          probability: opp.probability
        }))
      };

      const response = await fetch('/api/ai/crm-insights', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          inputs: {
            pipeline_data: JSON.stringify(payload)
          }
        })
      });

      if (!response.ok) {
        throw new Error(`Failed to generate insights: ${response.statusText}`);
      }

      const data = await response.json();

      if (data.error) {
        throw new Error(data.error);
      }

      if (data.result && typeof data.result === 'object') {
        setInsights(data.result);
      } else {
        throw new Error("Invalid format received from AI.");
      }
    } catch (err: any) {
      console.error("AI Insight generation error:", err);
      setError(err.message || 'An error occurred during AI analysis. Please verify the AI Service configuration.');
    } finally {
      setLoading(false);
    }
  };

  const hasAccess = accessibleModules.includes('quotations') || accessibleModules.includes('crm');

  // Fallback UI if not generated yet
  if (!insights && !loading && !error) {
    return (
      <div className="bg-[#111827] rounded-2xl border border-slate-800 shadow-xl p-6 relative h-full flex flex-col w-full h-full max-w-sm mx-auto">
        <div className="flex items-center justify-between mb-5 pb-3 border-b border-slate-800">
          <div className="flex items-center gap-2">
            <span className="w-8 h-8 flex items-center justify-center rounded-full bg-blue-500/10">
              <span className="material-symbols-outlined text-blue-400 text-xl">psychology</span>
            </span>
            <h4 className="font-bold text-base text-white tracking-wider uppercase">
              AI PIPELINE INSIGHTS
            </h4>
          </div>
          <div className="w-2 h-2 bg-slate-500 rounded-full"></div>
        </div>

        <div className="flex-1 flex flex-col items-center justify-center text-center p-4">
          <span className="material-symbols-outlined text-4xl text-slate-600 mb-4">analytics</span>
          <h3 className="text-white font-semibold mb-2">Ready for Analysis</h3>
          <p className="text-xs text-slate-400 mb-6 leading-relaxed">
            Generate an AI-driven executive summary of your active pipeline. This analyzes at-risk deals and high-probability opportunities to recommend the best next actions.
          </p>

          <button 
            onClick={handleGenerateInsights}
            disabled={!hasAccess || (atRiskDeals.length === 0 && highProbOpportunities.length === 0)}
            className="w-full bg-blue-600 hover:bg-blue-500 disabled:bg-slate-800 disabled:text-slate-500 text-white font-bold py-3 px-4 rounded-xl text-xs transition uppercase tracking-wider flex items-center justify-center gap-2"
          >
            <span className="material-symbols-outlined text-sm">auto_awesome</span>
            {hasAccess ? "Generate Executive Summary" : "Access Restricted"}
          </button>

          {(atRiskDeals.length === 0 && highProbOpportunities.length === 0) && hasAccess && (
             <p className="text-[10px] text-amber-500/80 mt-3">Not enough CRM data to analyze.</p>
          )}
        </div>
      </div>
    );
  }

  // Loading State
  if (loading) {
     return (
        <div className="bg-[#111827] rounded-2xl border border-slate-800 shadow-xl p-6 relative h-full flex flex-col w-full h-full max-w-sm mx-auto">
          <div className="flex items-center justify-between mb-5 pb-3 border-b border-slate-800">
            <div className="flex items-center gap-2">
              <span className="w-8 h-8 flex items-center justify-center rounded-full bg-blue-500/10">
                <span className="material-symbols-outlined text-blue-400 text-xl animate-pulse">psychology</span>
